import com.santaba.agent.groovyapi.expect.Expect;
import com.santaba.agent.groovyapi.snmp.Snmp;
import com.santaba.agent.groovyapi.http.*;
import com.santaba.agent.groovyapi.jmx.*;
import org.xbill.DNS.*;
//ADDED MANUALLY
import org.apache.http.client.methods.CloseableHttpResponse
import org.apache.http.client.methods.HttpGet
import org.apache.http.client.methods.HttpPost
import org.apache.http.impl.client.CloseableHttpClient
import org.apache.http.impl.client.HttpClients
import org.apache.http.util.EntityUtils
import javax.net.ssl.X509TrustManager
import javax.net.ssl.TrustManager
import java.security.cert.X509Certificate
import java.security.cert.CertificateException
import javax.net.ssl.HostnameVerifier
import javax.net.ssl.HttpsURLConnection
import javax.net.ssl.SSLContext
import java.security.SecureRandom
import org.apache.http.conn.ssl.NoopHostnameVerifier
import org.apache.http.entity.StringEntity
import org.json.JSONObject
import org.json.JSONArray
import groovy.json.JsonOutput

// get the host, credentials, and mgmt station baseurl from the device property table
hostname = hostProps.get("system.hostname");
userid = hostProps.get("tegile.user");
passwd = hostProps.get("tegile.pass");
base_url = "https://" + hostname;
//create auth Base64 encryption
auth_raw = userid + ":" + passwd
auth = auth_raw.bytes.encodeBase64().toString()

poolArray=[]

// construct the full endpoint url
endpoint_url = base_url + "/zebi/api/v2/listPools"; //LIST POOLS
method = "get"
get_pools = APIrequest(endpoint_url,auth,method)

if (get_pools != 404){
	// iterate over the json_object 
	for (int i=0; i<get_pools.length();i++){
		JSONObject obj = get_pools.get(i);

		pool_name = obj.getString("name");
		poolArray.add(pool_name) //store the pool in the poolArray (to further iterate over it)
	}

	//iterate over the newly built pool(s) array
	poolArray.each{
		pool_iterate=it

		//query the projects for the Pool in question
		endpoint_url = base_url + "/zebi/api/v2/listProjects"; //LIST POOLS
		method = "post"
		pool_name='"'+pool_iterate+'", true'
		post_reply=false
		get_projects_withinPool = APIrequest(endpoint_url,auth,method,pool_name,post_reply)

		for (int i=0; i<get_projects_withinPool.length();i++){
			JSONObject obj = get_projects_withinPool.get(i);

			projectName = obj["name"]
			projectName_wildvalue = SpecialCharacterCheck(projectName)

			println projectName_wildvalue+"##"+projectName+"##"+pool_iterate
		}
	}

	return(0);
}

//function to perform API request
def APIrequest(endpoint_url,auth,method, pool_name="", post_reply=false, jsonOutput=true){
	// HTTP Get
	def trustAllCerts = [
		new X509TrustManager() {
			public X509Certificate[] getAcceptedIssuers() {
				return null
			}

			public void checkServerTrusted(X509Certificate[] certs, String authType) throws CertificateException {
			}

			public void checkClientTrusted(X509Certificate[] certs, String authType) throws CertificateException {
			}
		}
	] as TrustManager[] 


	SSLContext sc = SSLContext.getInstance("SSL");
	sc.init(null, trustAllCerts, new SecureRandom());
	CloseableHttpClient httpclient = HttpClients.custom().setSSLHostnameVerifier(NoopHostnameVerifier.INSTANCE).setSslcontext(sc).build();

	if(method=="get"){
		httpGet = new HttpGet(endpoint_url); //SIMPLE GET - Without Params
		httpGet.addHeader("content-type", "application/json"); //GET header
		httpGet.addHeader("Authorization", "Basic "+auth); //GET header
		response = httpclient.execute(httpGet); //GET response
	}

	if(method=="post"){
		httpPost = new HttpPost(endpoint_url);
		httpPost.addHeader("content-type", "application/json"); //POST header
		httpPost.addHeader("Authorization", "Basic "+auth); //POST header

		json = '['+pool_name+']'
		entity = new StringEntity(json);
		httpPost.setEntity(entity);//POST Entity (params)

		//response = httpclient.execute(httpGet); //GET response
		response = httpclient.execute(httpPost); //POST response
	}

	responseBody = EntityUtils.toString(response.getEntity());
	code = response.getStatusLine().getStatusCode();

	httpclient.close();

	if(code==200){
		if(method=="get"){
			if(jsonOutput==true){
				if(post_reply==false){
					JSONArray response_ob = new JSONArray(responseBody);
					return response_ob;//return response
				}else{
					reponseBody_raw = "["+responseBody+"]" //ADD [] to expression (otherwise JSONArray fails)
					JSONArray response_ob = new JSONArray(reponseBody_raw);
					return response_ob;//return response
				}
			}else{
				return responseBody;
			}
		}

		if(method=="post"){
			if(post_reply==false){
				JSONArray response_ob = new JSONArray(responseBody);
				return response_ob;//return response
			}else{
				reponseBody_raw = "["+responseBody+"]" //ADD [] to expression (otherwise JSONArray fails)
				JSONArray response_ob = new JSONArray(reponseBody_raw);
				return response_ob;//return response
			}
		}
	}else{
		return(404);
	}
}

//according to :
//https://www.logicmonitor.com/support/logicmodules/datasources/active-discovery/script-active-discovery
//active discovery WILDVALUE cannot contain  ['=',':','\','#','space'] characters
//the function below will get rid of those special characters if they exist
def SpecialCharacterCheck(value){
	//special characters not allowed in ActiveDiscovery
	def specialCharacters = ~/\=|\:|\\|\#|\s/

	//replace the special character by nothing & return the 'new' service name
	value=value.replaceAll(specialCharacters, '')
	//println(service); //DEBUG

	return value
}

