// get the host, credentials, and mgmt station baseurl from the device property table
hostname = hostProps.get("system.hostname");
userid = hostProps.get("tegile.user");
passwd = hostProps.get("tegile.pass");
base_url = "https://" + hostname;
//create auth Base64 encryption
auth_raw = userid + ":" + passwd
auth = auth_raw.bytes.encodeBase64().toString()

poolArray=[]

// construct the full endpoint url
endpoint_url = base_url + "/zebi/api/v2/listPools"; //LIST POOLS
method = "get"
get_pools = APIrequest(endpoint_url,auth,method)

if (get_pools != 404){
	// iterate over the json_object 
	for (int i=0; i<get_pools.length();i++){
		JSONObject obj = get_pools.get(i);

		pool_name = obj.getString("name");

		poolArray.add(pool_name) //store the pool in the poolArray (to further iterate over it)
	}

	//iterate over the newly built pool(s) array
	poolArray.each{
		pool_iterate=it

		//query the projects for the Pool in question
		endpoint_url = base_url + "/zebi/api/v2/listProjects"; //LIST POOLS
		method = "post"
		pool_name='"'+pool_iterate+'", true'
		post_reply=false
		get_projects_withinPool = APIrequest(endpoint_url,auth,method,pool_name,post_reply)

		for (int i=0; i<get_projects_withinPool.length();i++){
			JSONObject obj1 = get_projects_withinPool.get(i);

			projectName = obj1["name"]
			projectName_wildvalue = SpecialCharacterCheck(projectName)

			//get admin details for each project
			endpoint_url = base_url + "/zebi/api/v2/getProject"; //LIST POOLS
			method = "post"
			pool_name='"'+pool_iterate+'", "'+projectName+'", true'
			post_reply=true
			get_project_details = APIrequest(endpoint_url,auth,method,pool_name,post_reply)		

			for (int z=0; z<get_project_details.length();z++){
				JSONObject obj2 = get_project_details.get(z);

				defaultVolumeSizeInByte = obj2["defaultVolumeSizeInByte"]
				quotaEnabled_raw = obj2["quotaEnabled"] 
					if(quotaEnabled_raw == true){quotaEnabled=1}else{quotaEnabled=0}//check if it's true or false & convert to 0/1
				quotaInByte = obj2["quotaInByte"]
				copies = obj2["copies"]
				dedup_raw = obj2["dedup"] 
					if(dedup_raw == "on"){dedup=1}else{dedup=0}//on/off - convert to 0/1

				println projectName_wildvalue+".defaultVolumeSizeInByte="+defaultVolumeSizeInByte
				println projectName_wildvalue+".quotaEnabled="+quotaEnabled
				println projectName_wildvalue+".quotaInByte="+quotaInByte
				println projectName_wildvalue+".copies="+copies
				println projectName_wildvalue+".dedup="+dedup
			}

			//get data analytics details for each project
			endpoint_url = base_url + "/zebi/api/v2/getOneMinuteDataAnalyticsHistory"; //LIST POOLS
			method = "post"
			pool_name='["'+pool_iterate+'/'+projectName+'"], null, null'
			post_reply=false
			get_project__data_details = APIrequest(endpoint_url,auth,method,pool_name,post_reply)

			for (int x=0; x<get_project__data_details.length();x++){
				JSONObject obj3 = get_project__data_details.get(x);

				Read_MBps = obj3["averages"]["Read_MBps"]
				Write_MBps = obj3["averages"]["Write_MBps"]
				Total_MBps = obj3["averages"]["Total_MBps"]
				Read_Ops = obj3["averages"]["Read_Ops"]
				Write_Ops = obj3["averages"]["Write_Ops"]
				Total_Ops = obj3["averages"]["Total_Ops"]
				Read_Latency = obj3["averages"]["Read_Latency"]
				Write_Latency = obj3["averages"]["Write_Latency"]
				Average_Latency = obj3["averages"]["Average_Latency"]

				println projectName_wildvalue+".Read_MBps="+Read_MBps
				println projectName_wildvalue+".Write_MBps="+Write_MBps
				println projectName_wildvalue+".Total_MBps="+Total_MBps
				println projectName_wildvalue+".Read_Ops="+Read_Ops
				println projectName_wildvalue+".Write_Ops="+Write_Ops
				println projectName_wildvalue+".Total_Ops="+Total_Ops
				println projectName_wildvalue+".Read_Latency="+Read_Latency
				println projectName_wildvalue+".Write_Latency="+Write_Latency
				println projectName_wildvalue+".Average_Latency="+Average_Latency
			}

			//get space info details for each project
			endpoint_url = base_url + "/zebi/api/v2/getDatasetSpaceInfo"; //LIST POOLS
			method = "post"
			pool_name='"'+pool_iterate+'/Local/'+projectName+'"'
			post_reply=true
			get_project__space_details = APIrequest(endpoint_url,auth,method,pool_name,post_reply)

			for (int y=0; y<get_project__space_details.length();y++){
				JSONObject obj4 = get_project__space_details.get(y);

				originalUsedByDataAndSnapshot = obj4["originalUsedByDataAndSnapshot"]
				usedByDataAndSnapshot = obj4["usedByDataAndSnapshot"]
				compressionSavingsPercentage = obj4["compressionSavingsPercentage"]
				available = obj4["available"]
				usedByData = obj4["usedByData"]
				usedBySnapshot = obj4["usedBySnapshot"]
				usedByReservation = obj4["usedByReservation"]
				quota = obj4["quota"]
				volSize = obj4["volSize"]

				println projectName_wildvalue+".originalUsedByDataAndSnapshot="+originalUsedByDataAndSnapshot
				println projectName_wildvalue+".usedByDataAndSnapshot="+usedByDataAndSnapshot
				println projectName_wildvalue+".compressionSavingsPercentage="+compressionSavingsPercentage
				println projectName_wildvalue+".available="+available
				println projectName_wildvalue+".usedByData="+usedByData
				println projectName_wildvalue+".usedBySnapshot="+usedBySnapshot
				println projectName_wildvalue+".usedByReservation="+usedByReservation
				println projectName_wildvalue+".quota="+quota
				println projectName_wildvalue+".volSize="+volSize
			}
		}
	}
	return(0);
}

